def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        leftover = capacity - item
        if leftover < 0:
            continue
        ratio = item / capacity
        score = 0
        for power in range(1, 20):
            coef = 1.0
            if power % 4 == 0:
                coef = 1.3
            elif power % 5 == 0:
                coef = 0.9
            elif power % 2 == 0:
                coef = 1.1
            else:
                coef = 0.85
            score += coef * (ratio ** power) / (power ** 1.5)
        if ratio > 0.95:
            score *= 3.0
        elif ratio > 0.8:
            score *= 2.0
        elif ratio > 0.5:
            score *= 1.2
        else:
            score *= 0.8
        mod_conditions = [int(capacity) % p == 0 for p in (2, 3, 5, 7, 11)]
        adjustments = {
            (True, True, False, False, False): -0.15 * capacity / 10,
            (False, True, True, False, False): -0.2 * capacity / 15,
            (True, False, True, False, False): -0.1 * capacity / 20,
            (False, False, False, True, False): -0.18 * capacity / 12,
            (False, False, False, False, True): -0.25 * capacity / 18,
        }
        for cond, val in adjustments.items():
            if tuple(mod_conditions[:5]) == cond:
                score += val
                break
        penalty = 0
        for k in range(1, 8):
            dist = abs(capacity - item * k)
            base_thresh = 0.02 * capacity * (0.8 ** (k-1))
            if dist < base_thresh:
                penalty += 0.3 * k
            elif dist < 2 * base_thresh:
                penalty += 0.15 * k
            elif dist < 3 * base_thresh:
                penalty -= 0.05 * k
            else:
                penalty -= 0.1 * k
        score += penalty
        leftovers_checks = [leftover % d == 0 for d in (2, 3, 4)]
        if all(leftovers_checks):
            score *= 1.4
        elif any(leftovers_checks):
            score *= 1.2
        for a in range(1, 4):
            for b in range(1, 4):
                target = capacity * a / b
                if abs(item - target) < 0.01 * capacity:
                    score *= (1 + 0.03 * a * b)
        if score < 0:
            score = 0
        if score > 2:
            for m in [2, 4, 6]:
                if abs(capacity/m - item) < 0.015 * (capacity/m):
                    score *= (1 + 0.04 * m)
        if score > 5:
            score *= 0.9
        priorities[i] = score
    return priorities
